import { WorkEntry, AdvanceEntry, UserSettings, WorkStatus, ExpenseEntry } from '../types';
import { format, subDays, startOfMonth } from 'date-fns';
import { supabase } from './supabaseClient';

const KEYS = {
  WORK_ENTRIES: 'mrt_work_entries',
  ADVANCES: 'mrt_advances',
  EXPENSES: 'mrt_expenses',
  SETTINGS: 'mrt_settings',
  LAST_NOTIF: 'mrt_last_notification_date'
};

// --- FUNÇÕES AUXILIARES ---

export const clearLocalData = () => {
  localStorage.removeItem(KEYS.WORK_ENTRIES);
  localStorage.removeItem(KEYS.ADVANCES);
  localStorage.removeItem(KEYS.EXPENSES);
  localStorage.removeItem(KEYS.SETTINGS);
  // Não limpamos LAST_NOTIF necessariamente, mas podemos se quiser resetar o aviso
};

// --- FUNÇÕES DE SINCRONIZAÇÃO COM SUPABASE (TABELA historico_ia) ---

// Envia dados para o Supabase (Background Sync) - Retorna TRUE se salvou ok
const syncKeyToSupabase = async (key: string, data: any): Promise<boolean> => {
  // 1. Pega o usuário logado ATUAL
  const { data: { session } } = await supabase.auth.getSession();

  // Se não tem usuário, não salva na nuvem (apenas local)
  if (!session?.user) return false; 

  try {
    // 2. Faz o Upsert usando o ID do usuário
    const { error } = await supabase
      .from('historico_ia')
      .upsert(
        { 
          user_id: session.user.id, // GARANTE que o dado é deste usuário
          category: key, 
          data: data,
          updated_at: new Date().toISOString()
        },
        { onConflict: 'user_id, category' }
      );

    if (error) {
        console.error(`Erro ao sincronizar ${key}:`, error);
        return false;
    }
    return true;
  } catch (err) {
    console.error("Erro de conexão ao salvar no banco:", err);
    return false;
  }
};

// Baixa todos os dados do Supabase ao iniciar (Load)
export const fetchAllFromSupabase = async (): Promise<boolean> => {
  const { data: { session } } = await supabase.auth.getSession();
  if (!session?.user) return false;

  try {
    // CORREÇÃO CRÍTICA:
    // Não limpamos os dados locais ANTES de baixar.
    // Primeiro baixamos. Se der erro (sem internet), mantemos os dados locais do usuário.

    const { data, error } = await supabase
      .from('historico_ia')
      .select('category, data')
      .eq('user_id', session.user.id);

    if (error) throw error;

    if (data && data.length > 0) {
      // SUCESSO: O servidor respondeu com dados.
      // Agora é seguro atualizar o LocalStorage.
      data.forEach(row => {
        // Verifica se o dado é válido antes de salvar
        if (row.data) {
             localStorage.setItem(row.category, JSON.stringify(row.data));
        }
      });
      return true;
    }

    // Se chegou aqui, conectou mas não tem dados no servidor (usuário novo).
    // Mantemos o que está local ou o app inicia zerado naturalmente.
    return true; 
  } catch (err) {
    console.error("Erro ao baixar dados do Supabase (Usando cache local):", err);
    // Retornamos false, mas NÃO limpamos os dados. 
    // O usuário verá os dados que já estavam no celular (Offline Mode).
    return false;
  }
};

// --- GETTERS (Leitura Local - Rápida) ---
// Adicionado try-catch para proteger contra dados corrompidos

export const getWorkEntries = (): WorkEntry[] => {
  try {
    const data = localStorage.getItem(KEYS.WORK_ENTRIES);
    if (!data) return [];
    const parsed = JSON.parse(data);
    return Array.isArray(parsed) ? parsed : [];
  } catch (e) {
    console.error("Erro ao ler registros:", e);
    return [];
  }
};

export const getAdvances = (): AdvanceEntry[] => {
  try {
    const data = localStorage.getItem(KEYS.ADVANCES);
    if (!data) return [];
    const parsed = JSON.parse(data);
    return Array.isArray(parsed) ? parsed : [];
  } catch (e) {
    console.error("Erro ao ler vales:", e);
    return [];
  }
};

export const getExpenses = (): ExpenseEntry[] => {
  try {
    const data = localStorage.getItem(KEYS.EXPENSES);
    if (!data) return [];
    const parsed = JSON.parse(data);
    return Array.isArray(parsed) ? parsed : [];
  } catch (e) {
    console.error("Erro ao ler despesas:", e);
    return [];
  }
};

export const getSettings = (): UserSettings => {
  const defaultSettings: UserSettings = {
    dailyRate: 200,
    workerName: '',
    employerName: '',
    currency: 'BRL',
    theme: 'light',
    notificationEnabled: false,
    notificationTime: '18:00',
    billingCycleStartDate: format(startOfMonth(new Date()), 'yyyy-MM-dd') // Padrão: dia 1 do mês atual
  };

  try {
    const data = localStorage.getItem(KEYS.SETTINGS);
    if (data) {
        const parsed = JSON.parse(data);
        return { ...defaultSettings, ...parsed };
    }
  } catch (e) {
    console.error("Erro ao ler configurações:", e);
  }

  return defaultSettings;
};

// --- SETTERS (Escrita Local + Sincronização Nuvem) ---

export const saveWorkEntry = (entry: WorkEntry) => {
  const entries = getWorkEntries();
  const index = entries.findIndex(e => e.id === entry.id);

  if (index >= 0) {
    entries[index] = entry;
  } else {
    entries.push(entry);
  }

  // Salva local
  localStorage.setItem(KEYS.WORK_ENTRIES, JSON.stringify(entries));
  // Sincroniza nuvem
  syncKeyToSupabase(KEYS.WORK_ENTRIES, entries);
};

export const deleteWorkEntry = (id: string) => {
  const entries = getWorkEntries();
  const newEntries = entries.filter(e => e.id !== id);

  localStorage.setItem(KEYS.WORK_ENTRIES, JSON.stringify(newEntries));
  syncKeyToSupabase(KEYS.WORK_ENTRIES, newEntries);
};

export const saveAdvance = (advance: AdvanceEntry) => {
  const advances = getAdvances();
  const index = advances.findIndex(a => a.id === advance.id);
  if (index >= 0) {
    advances[index] = advance;
  } else {
    advances.push(advance);
  }

  localStorage.setItem(KEYS.ADVANCES, JSON.stringify(advances));
  syncKeyToSupabase(KEYS.ADVANCES, advances);
};

export const deleteAdvance = (id: string) => {
  const advances = getAdvances().filter(a => a.id !== id);

  localStorage.setItem(KEYS.ADVANCES, JSON.stringify(advances));
  syncKeyToSupabase(KEYS.ADVANCES, advances);
};

export const saveExpense = (expense: ExpenseEntry) => {
  const expenses = getExpenses();
  const index = expenses.findIndex(e => e.id === expense.id);
  if (index >= 0) {
    expenses[index] = expense;
  } else {
    expenses.push(expense);
  }

  localStorage.setItem(KEYS.EXPENSES, JSON.stringify(expenses));
  syncKeyToSupabase(KEYS.EXPENSES, expenses);
};

export const deleteExpense = (id: string) => {
  const expenses = getExpenses();
  const newExpenses = expenses.filter(e => e.id !== id);

  localStorage.setItem(KEYS.EXPENSES, JSON.stringify(newExpenses));
  syncKeyToSupabase(KEYS.EXPENSES, newExpenses);
};

export const saveSettings = (settings: UserSettings) => {
  localStorage.setItem(KEYS.SETTINGS, JSON.stringify(settings));
  syncKeyToSupabase(KEYS.SETTINGS, settings);
};

// --- Helpers para Notificação ---
export const setLastNotificationDate = (dateStr: string) => {
    localStorage.setItem(KEYS.LAST_NOTIF, dateStr);
}

export const getLastNotificationDate = (): string | null => {
    return localStorage.getItem(KEYS.LAST_NOTIF);
}

// --- FUNÇÕES DE BACKUP (Arquivo Físico) ---

export const exportAllData = (): string => {
  const backupData = {
    workEntries: getWorkEntries(),
    advances: getAdvances(),
    expenses: getExpenses(),
    settings: getSettings(),
    exportedAt: new Date().toISOString(),
    appVersion: '1.2'
  };
  return JSON.stringify(backupData);
};

// Agora é ASYNC para garantir que sobe pro banco antes de dar refresh
export const importAllData = async (jsonString: string): Promise<boolean> => {
  try {
    const data = JSON.parse(jsonString);

    if (!data.workEntries || !data.advances || !data.settings) {
      throw new Error("Arquivo de backup inválido.");
    }

    // 1. Salva Localmente
    localStorage.setItem(KEYS.WORK_ENTRIES, JSON.stringify(data.workEntries));
    localStorage.setItem(KEYS.ADVANCES, JSON.stringify(data.advances));

    if (data.expenses) {
      localStorage.setItem(KEYS.EXPENSES, JSON.stringify(data.expenses));
    } else {
      localStorage.setItem(KEYS.EXPENSES, JSON.stringify([]));
    }
    localStorage.setItem(KEYS.SETTINGS, JSON.stringify(data.settings));

    // 2. Aguarda Sincronização com a Nuvem (CRÍTICO)
    const promises = [
        syncKeyToSupabase(KEYS.WORK_ENTRIES, data.workEntries),
        syncKeyToSupabase(KEYS.ADVANCES, data.advances),
        syncKeyToSupabase(KEYS.SETTINGS, data.settings)
    ];

    if(data.expenses) {
        promises.push(syncKeyToSupabase(KEYS.EXPENSES, data.expenses));
    }

    await Promise.all(promises);
    // Mesmo que o sync falhe (retorne false), o dado está local, então retornamos sucesso.

    return true;
  } catch (e) {
    console.error("Erro ao importar:", e);
    return false;
  }
};

// --- DADOS DE TESTE ---

export const generateTestData = () => {
  localStorage.clear();
  const today = new Date();
  const entries: WorkEntry[] = [];
  const advances: AdvanceEntry[] = [];
  const expenses: ExpenseEntry[] = [];

  const demoSettings: UserSettings = {
    dailyRate: 250,
    workerName: 'Trabalhador Exemplo',
    employerName: 'Construtora Modelo',
    currency: 'BRL',
    theme: 'light',
    notificationEnabled: false,
    notificationTime: '18:00',
    billingCycleStartDate: format(startOfMonth(today), 'yyyy-MM-dd')
  };

  // Salva e Sincroniza Settings
  saveSettings(demoSettings);

  for (let i = 0; i < 45; i++) {
    const date = subDays(today, i);
    if (date.getDay() === 0) continue;

    const dateStr = format(date, 'yyyy-MM-dd');
    const rand = Math.random();

    let status = WorkStatus.WORKED;
    let overtimeValue = undefined;
    let dailyRateSnapshot = 250;

    if (rand > 0.9) status = WorkStatus.HALF_DAY;
    else if (rand > 0.8) status = WorkStatus.MISSED;
    else if (rand > 0.5) overtimeValue = 50;

    if (status !== WorkStatus.MISSED) {
      entries.push({ id: dateStr, date: dateStr, status, dailyRateSnapshot, overtimeValue });
    }
  }

  advances.push({ id: 'demo_adv_1', date: format(subDays(today, 10), 'yyyy-MM-dd'), amount: 100, note: 'Gasolina' });
  advances.push({ id: 'demo_adv_2', date: format(subDays(today, 5), 'yyyy-MM-dd'), amount: 150, note: 'Almoço equipe' });

  expenses.push({ id: 'demo_exp_1', date: format(subDays(today, 12), 'yyyy-MM-dd'), amount: 80, note: 'Ferramenta nova' });
  expenses.push({ id: 'demo_exp_2', date: format(subDays(today, 3), 'yyyy-MM-dd'), amount: 45.50, note: 'Material para reparo' });

  // Salva no LocalStorage
  localStorage.setItem(KEYS.WORK_ENTRIES, JSON.stringify(entries));
  localStorage.setItem(KEYS.ADVANCES, JSON.stringify(advances));
  localStorage.setItem(KEYS.EXPENSES, JSON.stringify(expenses));

  // Força Sincronização
  syncKeyToSupabase(KEYS.WORK_ENTRIES, entries);
  syncKeyToSupabase(KEYS.ADVANCES, advances);
  syncKeyToSupabase(KEYS.EXPENSES, expenses);
};

import React, { useState, useRef, useEffect } from 'react';
import { UserSettings } from '../types';
import { saveSettings, exportAllData, importAllData, generateTestData } from '../services/storageService';
import { Card } from './ui/Card';
import { User, DollarSign, Briefcase, Download, Upload, Database, AlertTriangle, Wand2, Sun, Moon, Bell, Clock, Code, LogOut, Loader2, CalendarCheck, RotateCcw } from 'lucide-react';
import { format } from 'date-fns';

interface SettingsTabProps {
  settings: UserSettings;
  onSave: (newSettings: UserSettings) => void;
  onLogout: () => void;
}

const SettingsTab: React.FC<SettingsTabProps> = ({ settings, onSave, onLogout }) => {
  const [formData, setFormData] = useState<UserSettings>(settings);
  const [showSuccess, setShowSuccess] = useState(false);
  const [isImporting, setIsImporting] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [notificationPermission, setNotificationPermission] = useState<NotificationPermission>('default');

  useEffect(() => {
    if ('Notification' in window) {
      setNotificationPermission(Notification.permission);
    }
  }, []);

  const handleChange = (field: keyof UserSettings, value: any) => {
    const newSettings = { ...formData, [field]: value };
    setFormData(newSettings);
    if (field === 'theme') {
       onSave(newSettings);
       saveSettings(newSettings);
    }
  };

  const handleNotificationToggle = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const isChecked = e.target.checked;

    if (isChecked) {
        if (!('Notification' in window)) {
            alert("Este navegador não suporta notificações.");
            return;
        }

        if (Notification.permission === 'granted') {
            handleChange('notificationEnabled', true);
        } else {
            const permission = await Notification.requestPermission();
            setNotificationPermission(permission);
            if (permission === 'granted') {
                handleChange('notificationEnabled', true);
            } else {
                alert("Você precisa permitir notificações nas configurações do navegador para usar este recurso.");
                handleChange('notificationEnabled', false);
            }
        }
    } else {
        handleChange('notificationEnabled', false);
    }
  };

  const handleSave = () => {
    saveSettings(formData);
    onSave(formData);
    setShowSuccess(true);
    setTimeout(() => setShowSuccess(false), 3000);
  };

  const handleLogoutClick = () => {
    // Ação direta sem confirmação para evitar bloqueios de UI em mobile
    onLogout();
  };

  const handleResetCycle = () => {
     if(confirm("Deseja iniciar um novo ciclo de pagamentos a partir de HOJE? \n\nO saldo na aba Relatórios começará a ser contado desta data em diante.")) {
         const todayStr = format(new Date(), 'yyyy-MM-dd');
         handleChange('billingCycleStartDate', todayStr);
         // Auto-save para garantir
         const newSettings = { ...formData, billingCycleStartDate: todayStr };
         saveSettings(newSettings);
         onSave(newSettings);
         alert(`Novo ciclo iniciado em ${format(new Date(), 'dd/MM/yyyy')}!`);
     }
  }

  const handleExport = () => {
    const data = exportAllData();
    const blob = new Blob([data], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    const dateStr = format(new Date(), 'yyyy-MM-dd');
    link.href = url;
    link.download = `backup_registro_trabalho_${dateStr}.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleImportClick = () => {
    if (!isImporting) {
        fileInputRef.current?.click();
    }
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsImporting(true);

    const reader = new FileReader();
    reader.onload = async (event) => {
      const content = event.target?.result as string;

      // Agora espera o Supabase salvar antes de recarregar
      const success = await importAllData(content);

      if (success) {
        const updatedSettings = JSON.parse(content).settings;
        setFormData(updatedSettings);
        onSave(updatedSettings);
        alert("Dados restaurados com sucesso! O aplicativo será recarregado.");
        window.location.reload(); 
      } else {
        alert("Erro: Arquivo inválido ou corrompido.");
        setIsImporting(false);
      }
    };
    reader.readAsText(file);
    e.target.value = '';
  };

  const handleGenerateDemoData = () => {
    if (confirm("Atenção: Isso irá APAGAR todos os dados atuais e preencher com dados de exemplo. Deseja continuar?")) {
      generateTestData();
      window.location.reload();
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500 pb-10">
      <header className="flex justify-between items-center">
        <div>
            <h1 className="text-2xl font-bold text-slate-800 dark:text-white">Configurações</h1>
            <p className="text-slate-500 dark:text-slate-400">Seus dados e preferências</p>
        </div>
        <button 
            type="button"
            onClick={handleLogoutClick}
            className="shrink-0 p-3 bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-400 rounded-xl hover:bg-rose-100 hover:text-rose-600 transition-colors cursor-pointer active:scale-95"
            title="Sair do Aplicativo"
        >
            <LogOut className="w-6 h-6" />
        </button>
      </header>

      {/* NOVO CARD: FECHAMENTO DE CICLO */}
      <Card title="Ciclo de Pagamento / Fechamento" className="border-emerald-200 dark:border-emerald-900">
        <div className="flex items-start space-x-4">
            <div className="bg-emerald-100 dark:bg-emerald-900 p-2.5 rounded-full">
                <RotateCcw className="w-6 h-6 text-emerald-600 dark:text-emerald-300" />
            </div>
            <div className="flex-1">
                <p className="text-sm text-slate-600 dark:text-slate-300 mb-3">
                   Use isto quando receber um pagamento para <strong>zerar o saldo</strong> e começar a contar de novo, sem apagar o histórico.
                </p>

                <div className="mb-4">
                   <label className="block text-xs font-bold text-emerald-700 dark:text-emerald-400 mb-1 uppercase">Início do Ciclo Atual</label>
                   <input 
                      type="date"
                      value={formData.billingCycleStartDate || ''}
                      onChange={(e) => handleChange('billingCycleStartDate', e.target.value)}
                      className="w-full p-2 border-2 border-emerald-100 dark:border-emerald-800 rounded-xl bg-white dark:bg-slate-950 font-bold text-slate-800 dark:text-white"
                   />
                </div>

                <button 
                    onClick={handleResetCycle}
                    className="w-full py-2 bg-emerald-50 dark:bg-emerald-900/30 text-emerald-700 dark:text-emerald-300 border border-emerald-200 dark:border-emerald-800 rounded-xl text-sm font-bold hover:bg-emerald-100 transition-colors flex items-center justify-center gap-2"
                >
                    <CalendarCheck className="w-4 h-4" />
                    Recebi hoje! Reiniciar Saldo
                </button>
            </div>
        </div>
      </Card>

      <Card title="Notificações" className="border-violet-200 dark:border-violet-900">
        <div className="flex items-start space-x-4">
            <div className="bg-violet-100 dark:bg-violet-900 p-2.5 rounded-full">
                <Bell className="w-6 h-6 text-violet-600 dark:text-violet-300" />
            </div>
            <div className="flex-1">
                <div className="flex justify-between items-center mb-2">
                    <label className="text-slate-800 dark:text-white font-bold text-base" htmlFor="notif-toggle">
                        Lembrete Diário
                    </label>
                    <div className="relative inline-block w-12 h-6 align-middle select-none transition duration-200 ease-in">
                        <input 
                            type="checkbox" 
                            name="toggle" 
                            id="notif-toggle" 
                            checked={formData.notificationEnabled}
                            onChange={handleNotificationToggle}
                            className="toggle-checkbox absolute block w-6 h-6 rounded-full bg-white border-4 appearance-none cursor-pointer transition-all duration-300 ease-in-out checked:right-0 checked:border-emerald-500 right-6 border-slate-300"
                        />
                        <label 
                            htmlFor="notif-toggle" 
                            className={`toggle-label block overflow-hidden h-6 rounded-full cursor-pointer transition-colors duration-300 ${formData.notificationEnabled ? 'bg-emerald-500' : 'bg-slate-300 dark:bg-slate-700'}`}
                        ></label>
                    </div>
                </div>
                <p className="text-xs text-slate-500 dark:text-slate-400 mb-4">
                    Receba um aviso no celular para não esquecer de marcar o ponto.
                </p>

                {formData.notificationEnabled && (
                    <div className="bg-slate-50 dark:bg-slate-800 p-3 rounded-xl border border-slate-200 dark:border-slate-700 flex items-center justify-between animate-in fade-in slide-in-from-top-2">
                        <div className="flex items-center gap-2 text-slate-700 dark:text-slate-300">
                            <Clock className="w-4 h-4" />
                            <span className="text-sm font-bold">Horário do aviso:</span>
                        </div>
                        <input 
                            type="time" 
                            value={formData.notificationTime} 
                            onChange={(e) => handleChange('notificationTime', e.target.value)}
                            className="bg-white dark:bg-slate-900 border border-slate-300 dark:border-slate-600 rounded-lg px-2 py-1 text-sm font-bold text-slate-800 dark:text-white focus:ring-2 focus:ring-violet-500 outline-none"
